function setDataset(){let e=document.querySelector(".services-wrapper"),t=e.querySelectorAll(".service-item__content-wrapper"),i=e.querySelectorAll(".service-item__content");for(let e=0;e<i.length;e++)i[e].dataset.height=i[e].clientHeight,t[e].style.height=i[e].dataset.height+"px"}function showLinks(){let e=document.querySelector(".services-wrapper").querySelectorAll(".service-item");for(let t=0;t<e.length;t++)e[t].addEventListener("mouseenter",function(){window.innerWidth<920||(e[t].querySelector(".service-item__links-resizer").style.height=e[t].querySelector(".service-item__links-resizer > div").clientHeight+"px",e[t].querySelector(".service-item__content-wrapper").style.height=e[t].clientHeight+"px")}),e[t].addEventListener("mouseleave",function(){window.innerWidth<920||(e[t].querySelector(".service-item__links-resizer").style.height="0px",e[t].querySelector(".service-item__content-wrapper").style.height=e[t].querySelector(".service-item__content").dataset.height+"px")})}window.addEventListener("load",()=>{setDataset(),showLinks()}),window.addEventListener("resize",()=>{setDataset()});